(function(window, document){
  function parseBool(value) {
    return value === "true" || value === true;
  }

  function getTarget(element) {
    var selector = element.getAttribute("hx-target");
    if (!selector || selector === "this") {
      return element;
    }
    return document.querySelector(selector);
  }

  function applySwap(target, html, swapType) {
    if (!target) {
      return;
    }
    if (swapType === "outerHTML") {
      target.outerHTML = html;
      return;
    }
    if (swapType === "beforeend") {
      target.insertAdjacentHTML("beforeend", html);
      return;
    }
    target.innerHTML = html;
  }

  function setupElement(element) {
    if (element.dataset.htmxBound === "1") {
      return;
    }
    element.dataset.htmxBound = "1";
    var trigger = element.getAttribute("hx-trigger");
    if (!trigger) {
      trigger = "click";
    }

    var url = element.getAttribute("hx-get") || element.getAttribute("hx-post");
    if (!url) {
      return;
    }

    var method = element.getAttribute("hx-post") ? "POST" : "GET";
    var swapType = element.getAttribute("hx-swap") || "innerHTML";

    function fire() {
      var headers = {
        "HX-Request": "true"
      };

      fetch(url, {
        method: method,
        headers: headers,
        credentials: "same-origin"
      })
        .then(function(resp) {
          if (resp.status === 204) {
            if (element.parentNode) {
              element.remove();
            }
            return "";
          }
          return resp.text();
        })
        .then(function(html) {
          if (!html) {
            return;
          }
          var target = getTarget(element);
          applySwap(target, html, swapType);
          if (target && target.getAttribute && target.getAttribute("hx-onload") === "rebind") {
            return;
          }
          if (parseBool(element.getAttribute("hx-sync"))) {
            return;
          }
          if (typeof window.htmxOnSettle === "function") {
            window.htmxOnSettle();
          }
          var settled = new Event("htmx:afterSettle");
          document.body.dispatchEvent(settled);
          window.dispatchEvent(new Event("htmx:afterSettle"));
        })
        .catch(function() {
          return;
        });
    }

    if (trigger === "revealed") {
      var io = new IntersectionObserver(function(entries) {
        entries.forEach(function(entry) {
          if (entry.isIntersecting) {
            fire();
            io.disconnect();
          }
        });
      }, { root: null, threshold: 0.05 });
      io.observe(element);
      return;
    }

    if (trigger === "click") {
      element.addEventListener("click", function(event) {
        event.preventDefault();
        fire();
      });
    }

    if (trigger === "load") {
      window.addEventListener("DOMContentLoaded", fire, { once: true });
    }
  }

  function init() {
    var nodes = document.querySelectorAll("[hx-get], [hx-post]");
    for (var i = 0; i < nodes.length; i++) {
      setupElement(nodes[i]);
    }
    if (window.__gapcodeHtmxSettled !== true) {
      window.__gapcodeHtmxSettled = true;
      document.body.addEventListener("htmx:afterSettle", function() {
        init();
      }, false);
    }
    if (window.__gapcodeHtmxLoaded !== true) {
      window.__gapcodeHtmxLoaded = true;
      var loadEvent = new Event("htmx:load");
      document.body.dispatchEvent(loadEvent);
      window.dispatchEvent(new Event("htmx:load"));
    }
  }

  window.htmx = {
    init: init
  };

  window.addEventListener("DOMContentLoaded", init, { once: true });
})(window, document);
